const border = { style: BorderStyle.SINGLE, size: 1, color: 'AAAAAA' };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: 'FFFFFF' };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    pageBreakBefore: true,
    children: [new TextRun({ text, bold: true, size: 32, font: 'Times New Roman' })]
  });
}
function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 320, after: 160 },
    children: [new TextRun({ text, bold: true, size: 28, font: 'Times New Roman' })]
  });
}
function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 240, after: 120 },
    children: [new TextRun({ text, bold: true, italics: true, size: 26, font: 'Times New Roman' })]
  });
}
function p(text, opts = {}) {
  return new Paragraph({
    alignment: opts.center ? AlignmentType.CENTER : opts.right ? AlignmentType.RIGHT : AlignmentType.BOTH,
    spacing: { before: 0, after: 200, line: 360 },
    indent: opts.noIndent ? {} : { firstLine: 720 },
    children: [new TextRun({ text, size: 28, font: 'Times New Roman', bold: opts.bold, italics: opts.italic })]
  });
}
function pb() { return new Paragraph({ children: [new PageBreak()] }); }
function sp(n = 1) {
  return Array.from({ length: n }, () => new Paragraph({ spacing: { before: 0, after: 200 }, children: [new TextRun({ text: '', size: 28 })] }));
}
function bullet(text) {
  return new Paragraph({
    numbering: { reference: 'bullets', level: 0 },
    spacing: { before: 0, after: 120, line: 360 },
    children: [new TextRun({ text, size: 28, font: 'Times New Roman' })]
  });
}
function num(text) {
  return new Paragraph({
    numbering: { reference: 'numbers', level: 0 },
    spacing: { before: 0, after: 120, line: 360 },
    children: [new TextRun({ text, size: 28, font: 'Times New Roman' })]
  });
}
function code(text) {
  return new Paragraph({
    spacing: { before: 60, after: 60, line: 276 },
    indent: { left: 720 },
    children: [new TextRun({ text, size: 20, font: 'Courier New', color: '1a1a2e' })]
  });
}
function tblRow(cells, isHeader = false) {
  return new TableRow({
    tableHeader: isHeader,
    children: cells.map((txt, i) => new TableCell({
      borders,
      shading: isHeader ? { fill: '1a3a5c', type: ShadingType.CLEAR } : (i % 2 === 0 ? { fill: 'F5F7FA', type: ShadingType.CLEAR } : { fill: 'FFFFFF', type: ShadingType.CLEAR }),
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      children: [new Paragraph({
        children: [new TextRun({ text: txt, size: 24, font: 'Times New Roman', bold: isHeader, color: isHeader ? 'FFFFFF' : '000000' })]
      })]
    }))
  });
}

